const { execFile } = require('child_process');

function resizeImage(inputFilename, outputFilename, dimensions, effects) {
  const gmPath = '/usr/bin/gm'; // Path to GraphicsMagick executable
  const args = ['convert', inputFilename, '-resize', dimensions];

  effects.forEach(effect => {
    switch (effect.toLowerCase()) {
      case 'grayscale':
        args.push('-colorspace', 'gray');
        break;
      case 'sepia':
        args.push('-modulate', '100,50,50');
        break;
      case 'blur':
        args.push('-blur', '2x2');
        break;
      case 'enhance':
        args.push('-enhance');
        break;
      default:
        console.warn(`Unknown effect: ${effect}`);
    }
  });

  args.push(outputFilename);

  execFile(gmPath, args, (error, stdout, stderr) => {
    if (error) {
      console.error(`Error resizing image: ${stderr}`);
      return;
    }
    console.log(`Image resized successfully to ${outputFilename}`);
  });
}

// Example usage
resizeImage('user_photo.jpg', 'thumb.jpg', '200x200', ['grayscale', 'enhance']);